abstract class SensitiveDataScrubber {
  Map<String, dynamic> scrub(Map<String, dynamic> input);
}

class DefaultSensitiveDataScrubber implements SensitiveDataScrubber {
  static const _sensitiveKeys = {
    'card_number',
    'pan',
    'cvv',
    'cvc',
    'token',
    'client_secret',
    'authorization',
    'payment_method_token',
  };

  @override
  Map<String, dynamic> scrub(Map<String, dynamic> input) {
    final result = <String, dynamic>{};
    input.forEach((key, value) {
      if (_sensitiveKeys.contains(key.toLowerCase())) {
        result[key] = '***REDACTED***';
      } else if (value is Map<String, dynamic>) {
        result[key] = scrub(value);
      } else if (value is List) {
        result[key] = value.map((e) {
          if (e is Map<String, dynamic>) return scrub(e);
          return e;
        }).toList();
      } else {
        result[key] = value;
      }
    });
    return result;
  }
}

