class PlatformWalletService {
  static const MethodChannel _channel =
      MethodChannel('payment_processing_module/platform_wallet');

  final PaymentConfig config;

  PlatformWalletService(this.config);

  Future<bool> isWalletAvailable(PlatformWalletType type) async {
    final result = await _channel.invokeMethod<bool>('isAvailable', {
      'walletType': describeEnum(type),
      'merchantId': config.merchantId,
    });
    return result ?? false;
  }

  Future<String> tokenizePaymentData({
    required PlatformWalletType walletType,
    required PaymentAmount amount,
    required String label,
    required String countryCode,
  }) async {
    final result = await _channel.invokeMethod<String>('presentWallet', {
      'walletType': describeEnum(walletType),
      'merchantId': config.merchantId,
      'merchantDisplayName': config.merchantDisplayName,
      'amount': amount.minorUnits,
      'currency': amount.currency,
      'label': label,
      'countryCode': countryCode,
      'environment': describeEnum(config.environment),
    });
    if (result == null || result.isEmpty) {
      throw PaymentException('wallet_cancelled', 'Wallet payment was cancelled');
    }
    return result;
  }
}

class InAppPurchaseService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentLogger logger;

  StreamSubscription<List<PurchaseDetails>>? _subscription;

  InAppPurchaseService(this.logger);

  Future<bool> isAvailable() => _iap.isAvailable();

  Future<ProductDetailsResponse> queryProducts(Set<String> productIds) {
    return _iap.queryProductDetails(productIds);
  }

  void listen(
    Future<void> Function(PurchaseDetails purchase) onPurchase,
  ) {
    _subscription?.cancel();
    _subscription = _iap.purchaseStream.listen((purchases) async {
      for (final purchase in purchases) {
        logger.log('iap.purchase_update', {
          'productID': purchase.productID,
          'purchaseID': purchase.purchaseID,
          'status': purchase.status.name,
        });
        await onPurchase(purchase);
      }
    });
  }

  Future<void> buyConsumable(ProductDetails product) {
    final param = PurchaseParam(productDetails: product);
    return _iap.buyConsumable(purchaseParam: param);
  }

  Future<void> buyNonConsumable(ProductDetails product) {
    final param = PurchaseParam(productDetails: product);
    return _iap.buyNonConsumable(purchaseParam: param);
  }

  Future<void> completePurchase(PurchaseDetails purchase) async {
    if (purchase.pendingCompletePurchase) {
      await _iap.completePurchase(purchase);
    }
  }

  Future<void> dispose() async {
    await _subscription?.cancel();
  }
}

