class ReceiptVerificationService {
  final PaymentConfig config;
  final PaymentLogger logger;
  final http.Client _client;

  ReceiptVerificationService({
    required this.config,
    required this.logger,
    http.Client? client,
  }) : _client = client ?? http.Client();

  Future<PaymentResult> verify(ReceiptVerificationRequest request) async {
    final uri = config.gatewayBaseUrl.resolve('/payments/iap/verify');
    logger.log('verifyReceipt.request', request.toJson());
    try {
      final response = await _client
          .post(
            uri,
            headers: {
              'Content-Type': 'application/json',
              'Accept': 'application/json',
              'X-API-Version': config.apiVersion,
              'X-Publishable-Key': config.publishableKey,
              if (request.serverAuthToken != null)
                'Authorization': 'Bearer ${request.serverAuthToken}',
              ...config.defaultHeaders,
            },
            body: jsonEncode(request.toJson()),
          )
          .timeout(config.networkTimeout);
      final json = jsonDecode(response.body) as Map<String, dynamic>;
      logger.log('verifyReceipt.response', json);
      if (response.statusCode < 200 || response.statusCode >= 300) {
        throw PaymentException(
          json['error_code']?.toString() ?? 'receipt_verification_failed',
          json['message']?.toString() ?? 'Receipt verification failed',
          statusCode: response.statusCode,
          details: json,
        );
      }
      return PaymentResult.fromJson(json);
    } on TimeoutException {
      throw PaymentException('timeout', 'Receipt verification timed out');
    } on SocketException {
      throw PaymentException('network_error', 'No network connection');
    }
  }

  void dispose() {
    _client.close();
  }
}

class PciComplianceGuard {
  void assertNoRawCardData(Map<String, dynamic> payload) {
    final violations = <String>[];
    void walk(dynamic node, [String path = 'root']) {
      if (node is Map<String, dynamic>) {
        node.forEach((key, value) {
          final lower = key.toLowerCase();
          if (lower.contains('card_number') ||
              lower == 'pan' ||
              lower == 'cvv' ||
              lower == 'cvc' ||
              lower == 'expiry_month' ||
              lower == 'expiry_year') {
            violations.add('$path.$key');
          }
          walk(value, '$path.$key');
        });
      } else if (node is List) {
        for (var i = 0; i < node.length; i++) {
          walk(node[i], '$path[$i]');
        }
      }
    }

    walk(payload);
    if (violations.isNotEmpty) {
      throw PaymentException(
        'pci_violation',
        'Raw cardholder data detected in payload',
        details: {'violations': violations},
      );
    }
  }
}

class PaymentSecurity {
  static String generateIdempotencyKey({
    String? seed,
    int length = 32,
  }) {
    final raw =
        '${seed ?? ''}-${DateTime.now().microsecondsSinceEpoch}-${Random.secure().nextInt(1 << 32)}';
    final digest = sha256.convert(utf8.encode(raw)).toString();
    return digest.substring(0, min(length, digest.length));
  }

  static String hmacSha256(String secret, String payload) {
    final hmac = Hmac(sha256, utf8.encode(secret));
    return hmac.convert(utf8.encode(payload)).toString();
  }

  static bool constantTimeEquals(String a, String b) {
    if (a.length != b.length) return false;
    var diff = 0;
    for (var i = 0; i < a.length; i++) {
      diff |= a.codeUnitAt(i) ^ b.codeUnitAt(i);
    }
    return diff == 0;
  }
}

class PaymentProcessor {
  final PaymentConfig config;
  final PaymentLogger logger;
  final PaymentGatewayClient gatewayClient;
  final PlatformWalletService walletService;
  final InAppPurchaseService inAppPurchaseService;
  final ReceiptVerificationService receiptVerificationService;
  final SecureTokenStore secureTokenStore;
  final PciComplianceGuard pciComplianceGuard;

  PaymentProcessor({
    required this.config,
    PaymentLogger? logger,
    PaymentGatewayClient? gatewayClient,
    PlatformWalletService? walletService,
    InAppPurchaseService? inAppPurchaseService,
    ReceiptVerificationService? receiptVerificationService,
    SecureTokenStore? secureTokenStore,
    PciComplianceGuard? pciComplianceGuard,
  })  : logger = logger ??
            PaymentLogger(
              enabled: config.enableLogging && !config.isProduction,
            ),
        gatewayClient = gatewayClient ??
            PaymentGatewayClient(
              config: config,
              logger: logger ??
                  PaymentLogger(
                    enabled: config.enableLogging && !config.isProduction,
                  ),
            ),
        walletService = walletService ?? PlatformWalletService(config),
        inAppPurchaseService = inAppPurchaseService ??
            InAppPurchaseService(
              logger ??
                  PaymentLogger(
                    enabled: config.enableLogging && !config.isProduction,
                  ),
            ),
        receiptVerificationService = receiptVerificationService ??
            ReceiptVerificationService(
              config: config,
              logger: logger ??
                  PaymentLogger(
                    enabled: config.enableLogging && !config.isProduction,
                  ),
            ),
        secureTokenStore = secureTokenStore ?? SecureTokenStore(),
        pciComplianceGuard = pciComplianceGuard ?? PciComplianceGuard();

  Future<PaymentResult> processPayment({
    required PaymentRequest request,
    String? authToken,
  }) async {
    pciComplianceGuard.assertNoRawCardData(request.toJson());
    final json = await gatewayClient.createPaymentIntent(
      request,
      authToken: authToken,
    );
    return PaymentResult.fromJson(json);
  }

  Future<PaymentResult> processApplePay({
    required PaymentAmount amount,
    required String label,
    required String countryCode,
    CustomerInfo? customer,
    Map<String, dynamic> metadata = const {},
    String? authToken,
  }) async {
    if (!Platform.isIOS) {
      throw PaymentException('unsupported_platform', 'Apple Pay is only available on iOS');
    }
    final available =
        await walletService.isWalletAvailable(PlatformWalletType.applePay);
    if (!available) {
      throw PaymentException('wallet_unavailable', 'Apple Pay is not available');
    }

    final request = PaymentRequest(
      idempotencyKey: PaymentSecurity.generateIdempotencyKey(seed: 'apple_pay'),
      amount: amount,
      methodType: PaymentMethodType.applePay,
      customer: customer,
      metadata: metadata,
      captureImmediately: true,
    );

    final intent = await processPayment(request: request, authToken: authToken);
    final walletToken = await walletService.tokenizePaymentData(
      walletType: PlatformWalletType.applePay,
      amount: amount,
      label: label,
      countryCode: countryCode,
    );
    final confirmation = await gatewayClient.confirmWalletPayment(
      paymentIntentId: intent.transactionId,
      walletPayloadToken: walletToken,
      walletType: PlatformWalletType.applePay,
      authToken: authToken,
    );
    return PaymentResult.fromJson(confirmation);
  }

  Future<PaymentResult> processGooglePay({
    required PaymentAmount amount,
    required String label,
    required String countryCode,
    CustomerInfo? customer,
    Map<String, dynamic> metadata = const {},
    String? authToken,
  }) async {
    if (!Platform.isAndroid) {
      throw PaymentException('unsupported_platform', 'Google Pay is only available on Android');
    }
    final available =
        await walletService.isWalletAvailable(PlatformWalletType.googlePay);
    if (!available) {
      throw PaymentException('wallet_unavailable', 'Google Pay is not available');
    }

    final request = PaymentRequest(
      idempotencyKey: PaymentSecurity.generateIdempotencyKey(seed: 'google_pay'),
      amount: amount,
      methodType: PaymentMethodType.googlePay,
      customer: customer,
      metadata: metadata,
      captureImmediately: true,
    );

    final intent = await processPayment(request: request, authToken: authToken);
    final walletToken = await walletService.tokenizePaymentData(
      walletType: PlatformWalletType.googlePay,
      amount: amount,
      label: label,
      countryCode: countryCode,
    );
    final confirmation = await gatewayClient.confirmWalletPayment(
      paymentIntentId: intent.transactionId,
      walletPayloadToken: walletToken,
      walletType: PlatformWalletType.googlePay,
      authToken: authToken,
    );
    return PaymentResult.fromJson(confirmation);
  }

  Future<void> initializeInAppPurchases({
    Future<void> Function(PurchaseDetails purchase)? onPurchase,
  }) async {
    final available = await inAppPurchaseService.isAvailable();
    if (!available) {
      throw PaymentException('iap_unavailable', 'In-app purchases are not available');
    }
    if (onPurchase != null) {
      inAppPurchaseService.listen(onPurchase);
    }
  }

  Future<ProductDetailsResponse> loadInAppProducts() {
    return inAppPurchaseService.queryProducts(config.inAppProductIds.toSet());
  }

  Future<void> buyConsumable(ProductDetails product) {
    return inAppPurchaseService.buyConsumable(product);
  }

  Future<void> buyNonConsumable(ProductDetails product) {
    return inAppPurchaseService.buyNonConsumable(product);
  }

  Future<PaymentResult> verifyInAppPurchase(
    PurchaseDetails purchase, {
    String? authToken,
  }) async {
    final receiptData = purchase.verificationData.serverVerificationData;
    final source = Platform.isIOS ? 'app_store' : 'play_store';
    final request = ReceiptVerificationRequest(
      source: source,
      receiptData: receiptData,
      productId: purchase.productID,
      transactionId: purchase.purchaseID,
      purchaseToken: Platform.isAndroid ? receiptData : null,
      serverAuthToken: authToken,
    );
    final result = await receiptVerificationService.verify(request);
    await inAppPurchaseService.completePurchase(purchase);
    return result;
  }

  Future<PaymentResult> captureAuthorizedPayment(
    String paymentIntentId, {
    int? amountToCapture,
    String? authToken,
  }) async {
    final json = await gatewayClient.capturePayment(
      paymentIntentId,
      amountToCapture: amountToCapture,
      authToken: authToken,
    );
    return PaymentResult.fromJson(json);
  }

  Future<PaymentResult> refundTransaction(
    String transactionId, {
    int? amountToRefund,
    String? reason,
    String? authToken,
  }) async {
    final json = await gatewayClient.refundPayment(
      transactionId,
      amountToRefund: amountToRefund,
      reason: reason,
      authToken: authToken,
    );
    return PaymentResult.fromJson(json);
  }

  Future<PaymentResult> fetchTransactionStatus(
    String transactionId, {
    String? authToken,
  }) async {
    final json = await gatewayClient.fetchPaymentStatus(
      transactionId,
      authToken: authToken,
    );
    return PaymentResult.fromJson(json);
  }

  Future<void> dispose() async {
    gatewayClient.dispose();
    receiptVerificationService.dispose();
    await inAppPurchaseService.dispose();
  }
}

class PaymentWebhookVerifier {
  final String signingSecret;

  const PaymentWebhookVerifier(this.signingSecret);

  bool verify({
    required String payload,
    required String signature,
  }) {
    final computed = PaymentSecurity.hmacSha256(signingSecret, payload);
    return PaymentSecurity.constantTimeEquals(computed, signature);
  }
}

class PaymentModule {
  static PaymentProcessor create({
    required PaymentConfig config,
  }) {
    return PaymentProcessor(config: config);
  }
}